 1	import * as _ from 'lodash-es';
 2	import * as React from 'react';
 3	import { Helmet } from 'react-helmet';
 4	import { useTranslation } from 'react-i18next';
 5	
 6	import { usePerspective } from '../../hooks/usePerspective';
 7	import { DashboardDropdown } from './dashboard-dropdown';
 8	import { LegacyDashboardsAllVariableDropdowns } from '../legacy/legacy-variable-dropdowns';
 9	import { TimeDropdowns } from './time-dropdowns';
10	import { CombinedDashboardMetadata } from '../perses/hooks/useDashboardsData';
11	import { AllVariableDropdowns } from '../perses/variable-dropdowns';
12	import { useIsPerses } from './useIsPerses';
13	import { Divider, PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
14	
15	const HeaderTop: React.FC = React.memo(() => {
16	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
17	
18	  return (
19	    <div className="monitoring-dashboards__header">
20	      <Title headingLevel="h1">{t('Dashboards')}</Title>
21	      <TimeDropdowns />
22	    </div>
23	  );
24	});
25	
26	type MonitoringDashboardsPageProps = React.PropsWithChildren<{
27	  boardItems: CombinedDashboardMetadata[];
28	  changeBoard: (dashboardName: string) => void;
29	  dashboardName: string;
30	}>;
31	
32	const DashboardSkeleton: React.FC<MonitoringDashboardsPageProps> = ({
33	  children,
34	  boardItems,
35	  changeBoard,
36	  dashboardName,
37	}) => {
38	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
39	  const isPerses = useIsPerses();
40	
41	  const { perspective } = usePerspective();
42	
43	  return (
44	    <>
45	      {perspective !== 'dev' && (
46	        <Helmet>
47	          <title>{t('Metrics dashboards')}</title>
48	        </Helmet>
49	      )}
50	      <PageSection variant={PageSectionVariants.light}>
51	        {perspective !== 'dev' && <HeaderTop />}
52	        <div className="monitoring-dashboards__variables">
53	          <div className="monitoring-dashboards__dropdowns">
54	            {!_.isEmpty(boardItems) && (
55	              <DashboardDropdown
56	                items={boardItems}
57	                onChange={changeBoard}
58	                selectedKey={dashboardName}
59	              />
60	            )}
61	            {isPerses ? (
62	              <AllVariableDropdowns key={dashboardName} />
63	            ) : (
64	              <LegacyDashboardsAllVariableDropdowns key={dashboardName} />
65	            )}
66	          </div>
67	          {perspective === 'dev' && <TimeDropdowns />}
68	        </div>
69	      </PageSection>
70	      <Divider />
71	      {children}
72	    </>
73	  );
74	};
75	
76	export default DashboardSkeleton;

